    "environmental_status_signal",
    "cleaning_status_signal",
    "em_review_signal",
    "personnel_signal",
    "deviation_signal",
    "ingredient_signal",
    "approval_signal",
    "start_gate_status",
    "start_gate_decision",
    "readiness_score",
